sp_instance.widget_parameters:
{
	"html": {
		"value": "<style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            line-height: 1.6;
            color: #212529;
            background-color: #F5F5F5;
        }

        .container {
            max-width: 1200px;
            margin: 0 auto;
            padding: 20px;
        }

        h1 {
            text-align: center;
            color: #1E1E1E;
            font-size: 2.5em;
            margin: 40px 0;
            padding-bottom: 20px;
            border-bottom: 3px solid #D72828;
        }

        .service-section {
            display: flex;
            align-items: center;
            gap: 40px;
            margin: 60px 0;
            background: #FFFFFF;
            padding: 40px;
            border-radius: 10px;
            box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
        }

        .service-section.reverse {
            flex-direction: row-reverse;
        }

        .image-placeholder {
            flex: 1;
            min-width: 300px;
            height: 300px;
            background: linear-gradient(135deg, #D72828 0%, #1E1E1E 100%);
            border-radius: 8px;
            display: flex;
            align-items: center;
            justify-content: center;
            color: white;
            font-size: 1.2em;
            font-weight: bold;
            text-align: center;
            padding: 20px;
        }

        .service-section:nth-child(even) .image-placeholder {
            background: linear-gradient(135deg, #0076D6 0%, #1955BE 100%);
        }

        .service-section:nth-child(3) .image-placeholder {
            background: linear-gradient(135deg, #28A745 0%, #10171A 100%);
        }

        .service-section:nth-child(4) .image-placeholder {
            background: linear-gradient(135deg, #FFC107 0%, #D72828 100%);
        }

        .content {
            flex: 1;
        }

        .content h2 {
            color: #1E1E1E;
            font-size: 2em;
            margin-bottom: 20px;
        }

        .content p {
            color: #6C757D;
            font-size: 1.1em;
            margin-bottom: 20px;
            line-height: 1.8;
        }

        .content a {
            display: inline-block;
            color: #1955BE;
            text-decoration: none;
            font-weight: bold;
            font-size: 1.1em;
            padding: 10px 20px;
            border: 2px solid #D72828;
            border-radius: 5px;
            transition: all 0.3s ease;
        }

        .content a:hover {
            background-color: #D72828;
            color: white;
            transform: translateX(5px);
        }

        @media (max-width: 768px) {
            .service-section,
            .service-section.reverse {
                flex-direction: column;
            }

            .image-placeholder {
                width: 100%;
                min-width: auto;
            }

            h1 {
                font-size: 2em;
            }

            .content h2 {
                font-size: 1.5em;
            }
        }
    </style>
<div class="container">
<h1>How We Can Help</h1>
<!-- Section 1: Incident Management (Image Left, Text Right) -->
<div class="service-section">
<div class="image-placeholder"><img style="max-width: 100%; max-height: 480px;" src="/sys_attachment.do?sys_id=5a73386293dd8b90945375dcebba1021"></div>
<div class="content">
<h2>Incident Management</h2>
<p>Our incident management service ensures rapid response and resolution to minimize downtime. We provide 24/7 monitoring, automated alerting, and expert support to handle critical incidents efficiently.</p>
<a href="/itms?id=esc_sc_cat_item&amp;sys_id=3f1dd0320a0a0b99000a53f7604a2ef9">Report an Incident &rarr;</a></div>
</div>
<!-- Section 2: Feature Request Management (Image Left, Text Right) -->
<div class="service-section">
<div class="image-placeholder"><img style="max-width: 100%; max-height: 480px;" src="/sys_attachment.do?sys_id=5583786293dd8b90945375dcebba1084"></div>
<div class="content">
<h2>Feature Request Management</h2>
<p>Transform your ideas into reality with our streamlined feature request management process. We prioritize, track, and implement new features based on business value.</p>
<a href="/itms?id=esc_sc_cat_item&amp;sys_id=a0db11ed9399cf50945375dcebba1035">Raise a Feature Request &rarr;</a></div>
</div>
<!-- Section 3: Service Request Management (Text Left, Image Right) -->
<div class="service-section reverse">
<div class="image-placeholder"><img style="max-width: 100%; max-height: 480px;" src="/sys_attachment.do?sys_id=79933c6293dd8b90945375dcebba104a"></div>
<div class="content">
<h2>Service Request Management</h2>
<p>Simplify routine service requests with our automated workflow system. From digital product requests, employee requests, to hardware provisioning, we provide a user-friendly portal for efficient fulfillment.</p>
<a href="/itms?id=esc_sc_cat_item&amp;sys_id=d16049689359c350945375dcebba10d9">Raise a General Service Request &rarr;</a></div>
</div>
</div>",
